                Size = UDim2.new(0.5, 0, 1, 0),
                BackgroundTransparency = 1,
                Text = el.name or "Color Picker",
                TextColor3 = Theme.Colors.TextSecondary,
                Font = Theme.Fonts.Medium,
                TextSize = 13,
                TextXAlignment = Enum.TextXAlignment.Left,
            }),
            
            -- Info Tag
