            }, {
                Corner = React.createElement("UICorner", {
                    CornerRadius = Theme.CornerRadius.Element,
                }),
                Stroke = React.createElement("UIStroke", {
                    Color = Theme.Colors.Border,
                    Thickness = 1,
                }),
            }),
        }),
        
        -- Red Slider
        Red = React.createElement(require(Source.Components.Slider), {
            Store = Store,
            element = {
