                Size = UDim2.new(0, 20, 0, 20),
                Position = UDim2.new(0, 15, 0.5, -10),
                BackgroundTransparency = 1,
                Image = "rbxassetid://10734950309", -- Moon icon
                ImageColor3 = Theme.Colors.Accent,
