__modules["Packages/_Index/jsdotlua_collections@1.2.7/collections/src/Array/isArray"] = function()
    local script = createVirtualModule("Packages/_Index/jsdotlua_collections@1.2.7/collections/src/Array/isArray")
    local Source = createVirtualFolder("")
    local require = __require
    local ReplicatedStorage = ReplicatedStorage

return function(value: any): boolean
	if typeof(value) ~= "table" then
		return false
	end
	if next(value) == nil then
		-- an empty table is an empty array
		return true
	end

	local length = #value

	if length == 0 then
		return false
	end

	local count = 0
	local sum = 0
	for key in pairs(value) do
		if typeof(key) ~= "number" then
			return false
		end
		if key % 1 ~= 0 or key < 1 then
			return false
		end
		count += 1
		sum += key
	end

	return sum == (count * (count + 1) / 2)
end

end

